  ('Le Tajine de Poulet au Citron Confit', 'multiple_choice', 'Quelle partie du citron confit utilise-t-on dans le tajine ?', '["La peau uniquement","La pulpe uniquement","Les deux — pulpe et peau","Le jus extrait"]', 'La peau uniquement', 'La pulpe du citron confit est trop salée et amère — seule la peau parfumée est utilisée.', 1),
  ('Le Tajine de Poulet au Citron Confit', 'fill_in_blank', 'Le citron confit est fermenté dans le ___ pendant un mois', '[]', 'sel', 'La lacto-fermentation au sel transforme le citron et développe des saveurs umami complexes.', 2),
  ('La Harira Enrichie', 'multiple_choice', 'Lors de quel événement religieux la harira est-elle traditionnellement consommée ?', '["L iftar du Ramadan","L Aïd al-Adha","Le Mouloud","Le Nouvel An hégire"]', 'L iftar du Ramadan', 'La harira est LA soupe de rupture du jeûne — servie au coucher du soleil pendant tout le Ramadan.', 1),
  ('La Harira Enrichie', 'fill_in_blank', 'Le mélange farine-eau qui épaissit la harira s appelle le ___', '[]', 'tedouira', 'Le tedouira est ajouté en fin de cuisson et donne à la harira sa consistance caractéristique.', 2),
  ('La Trid au Poulet', 'multiple_choice', 'Lors de quel événement sert-on traditionnellement le trid ?', '["Les noces marocaines","Les funérailles","Le Ramadan","L anniversaire"]', 'Les noces marocaines', 'Le trid est le plat des mariages marocains — considéré comme un plat de prestige.', 1),
  ('La Trid au Poulet', 'fill_in_blank', 'Les crêpes feuilletées marocaines à la semoule s appellent ___', '[]', 'msemen', 'Le msemen est une crêpe feuilletée carrée — utilisée pour le trid et servie aussi au petit-déjeuner.', 2),
  ('Les Kemia Marocaines', 'multiple_choice', 'À quelle température servent-on les kemia ?', '["À température ambiante","Froides du réfrigérateur","Très chaudes","Tièdes seulement"]', 'À température ambiante', 'Les arômes des épices et de l huile d olive s expriment mieux à température ambiante.', 1),
  ('Les Kemia Marocaines', 'fill_in_blank', 'La marinade marocaine polyvalente aux herbes, épices et citron s appelle ___', '[]', 'chermoula', 'La chermoula est utilisée pour mariner le poisson, les légumes et comme sauce d accompagnement.', 2),
  ('Le Méchoui d Agneau', 'multiple_choice', 'À quels événements sert-on le méchoui ?', '["L Aïd et les mariages","Le Ramadan uniquement","Les anniversaires","Les fêtes nationales"]', 'L Aïd et les mariages', 'Le méchoui est le plat des grandes fêtes — son envergure (un agneau entier) demande une grande tablée.', 1),
  ('Le Méchoui d Agneau', 'fill_in_blank', 'L agneau doit être badigeonné toutes les ___ minutes pour rester juteux', '[]', '30', 'Le badigeonnage régulier (épices, beurre, huile) empêche le dessèchement et dore la peau.', 2),
  ('La Mrouzia Festive', 'multiple_choice', 'Lors de quelle fête prépare-t-on la mrouzia ?', '["L Aïd al-Adha","Le Ramadan","Le Mouloud","L Aïd el-Fitr"]', 'L Aïd al-Adha', 'La mrouzia est préparée avec la viande du mouton sacrifié lors de l Aïd al-Adha (fête du sacrifice).', 1),
  ('La Mrouzia Festive', 'fill_in_blank', 'Le ras el hanout contient entre ___ et 30 épices différentes', '[]', '20', 'Le ras el hanout (tête de l épicerie) est le mélange d épices le plus complexe du Maroc.', 2),
  ('Les Crêpes Baghrir Avancées', 'multiple_choice', 'Pourquoi la pâte à baghrir doit-elle reposer 30 minutes ?', '["Pour que les trous se forment à la cuisson","Pour lever","Pour épaissir","C est une tradition sans effet"]', 'Pour que les trous se forment à la cuisson', 'La fermentation courte crée des bulles de CO2 — elles percent la crêpe et créent les mille trous.', 1),
  ('Les Crêpes Baghrir Avancées', 'fill_in_blank', 'Le baghrir s appelle la crêpe à ___ trous', '[]', 'mille', 'Mille trous (baghrir) — la surface criblée de petits trous est la caractéristique distinctive.', 2),
  ('La Pastilla au Pigeon', 'multiple_choice', 'Quelle est la garniture originale de la pastilla ?', '["Pigeon","Poulet","Agneau","Crevettes"]', 'Pigeon', 'La pastilla originale est au pigeon — le poulet est une adaptation plus récente et plus accessible.', 1),
  ('La Pastilla au Pigeon', 'fill_in_blank', 'La feuille de pastilla marocaine ultra-fine s appelle la ___', '[]', 'warka', 'La warka est plus fine que le phyllo grec — elle est préparée en tamponnant la pâte sur une surface chaude.', 2),
  ('Le Couscous au Beurre Frais', 'multiple_choice', 'Combien de fois cuit-on le couscous à la vapeur pour la perfection ?', '["Trois fois","Une fois","Deux fois","Quatre fois"]', 'Trois fois', 'Trois passages vapeur avec roulage entre chaque garantissent des grains parfaitement séparés.', 1),
  ('Le Couscous au Beurre Frais', 'fill_in_blank', 'La marmite à deux niveaux pour cuire le couscous s appelle un ___', '[]', 'couscoussier', 'Le couscoussier a une marmite en bas pour le bouillon et un panier perforé en haut pour le couscous.', 2),
  ('La Soupe de Fèves Bessara', 'multiple_choice', 'Quel condiment est indispensable sur la bessara servie ?', '["Filet d huile d olive crue","Crème fraîche","Beurre fondu","Sauce harissa"]', 'Filet d huile d olive crue', 'L huile d olive crue versée sur la bessara chaude est fondamentale — jamais l omettre.', 1),
  ('La Soupe de Fèves Bessara', 'fill_in_blank', 'La bessara est le petit-déjeuner des ___ marocains', '[]', 'travailleurs', 'La bessara est nourrissante et bon marché — le petit-déjeuner populaire des classes laborieuses.', 2),
  ('Le Tajine de Sardines Farcies', 'multiple_choice', 'De quelle ville côtière ce tajine est-il populaire ?', '["Safi et Essaouira","Casablanca","Tanger","Agadir"]', 'Safi et Essaouira', 'Safi est la capitale de la sardine au Maroc — Essaouira est réputée pour ses poissons grillés.', 1),
  ('Le Tajine de Sardines Farcies', 'fill_in_blank', 'Les sardines sont farcies avec de la ___', '[]', 'chermoula', 'La chermoula (marinade marocaine) est la farce et sauce des sardines farcies.', 2),
  ('Les Sellou (Sfouf)', 'multiple_choice', 'Pour qui prépare-t-on le sellou traditionnellement ?', '["Les femmes enceintes ou accouchées et pour le Ramadan","Les hommes seulement","Les enfants","Les anciens"]', 'Les femmes enceintes ou accouchées et pour le Ramadan', 'Le sellou est très énergétique — il nourrit et réconforte les femmes après l accouchement.', 1),
  ('Les Sellou (Sfouf)', 'fill_in_blank', 'L épice caractéristique du sellou est l ___', '[]', 'anis', 'L anis vert donne son arôme distinctif au sellou — reconnaissable entre tous.', 2),
  ('Les Choumicha Kaab el Ghazal', 'multiple_choice', 'Que signifie kaab el ghazal en arabe ?', '["Cheville de gazelle","Patte de gazelle","Corne de gazelle","Œil de gazelle"]', 'Cheville de gazelle', 'La forme incurvée de la pâtisserie rappelle la cheville délicate d une gazelle.', 1),
  ('Les Choumicha Kaab el Ghazal', 'fill_in_blank', 'L eau de ___ d oranger parfume la pâtisserie marocaine de façon caractéristique', '[]', 'fleur', 'L eau de fleur d oranger (nasrate) est l arôme de base de toute la pâtisserie marocaine.', 2),
  ('Le Thé à la Menthe Cérémonie', 'multiple_choice', 'Comment verse-t-on le thé marocain et pourquoi ?', '["De haut pour créer la mousse — signe d hospitalité","Au ras du verre pour ne pas renverser","Dans la théière d abord","À l envers dans le verre"]', 'De haut pour créer la mousse — signe d hospitalité', 'La hauteur du versement crée la mousse qui oxygène le thé et signifie que le maître de maison est généreux.', 1),
  ('Le Thé à la Menthe Cérémonie', 'fill_in_blank', 'Le thé vert en billes utilisé pour le thé marocain s appelle ___', '[]', 'Gunpowder', 'Le thé Gunpowder (poudre à canon) est ainsi nommé car ses billes ressemblent à de la poudre noire.', 2),
  ('La Diffa Marocaine Complète', 'multiple_choice', 'Lors de quels événements sert-on la diffa ?', '["Mariages et Aid","Ramadan uniquement","Tous les jours du vendredi","Visites de dignitaires"]', 'Mariages et Aid', 'La diffa est le festin des grandes occasions — mariages, Aid et réceptions officielles.', 1),
  ('La Diffa Marocaine Complète', 'fill_in_blank', 'Diffa signifie ___ marocain en arabe', '[]', 'festin', 'La diffa (ضيافة) vient du mot arabe pour hospitalité — un festin est l expression suprême de l accueil.', 2)
) AS v(lesson_title, type, question, options, correct_answer, explanation, order_index)
JOIN public.lessons l ON l.title = v.lesson_title;
